/**

*

* -----------------------------------------------------------------------------

*

* Template : Educavo - Education HTML Template

* Author : rs-theme

* Author URI : http://www.rstheme.com/

*

* -----------------------------------------------------------------------------

*

**/



(function ($) {

    'use strict';

    // Get the form.

    var form = $('#contact-form');



    // Get the messages div.

    var formMessages = $('#form-messages');



    // Set up an event listener for the contact form.

    $(form).submit(function (e) {

        // Stop the browser from submitting the form.

        e.preventDefault();



        // Serialize the form data.

        var formData = $(form).serialize();



        // Submit the form using AJAX.

        $.ajax({

            type: 'POST',

            url: $(form).attr('action'),

            data: formData

        })

            .done(function (response) {

                // Make sure that the formMessages div has the 'success' class.

                $(formMessages).removeClass('error');

                $(formMessages).addClass('success');



                // Set the message text.

                $(formMessages).text(response);



                // Clear the form.

                $('#name, #email, #phone, #subject, #message').val('');

            })

            .fail(function (data) {

                // Make sure that the formMessages div has the 'error' class.

                $(formMessages).removeClass('success');

                $(formMessages).addClass('error');



                // Set the message text.

                if (data.responseText !== '') {

                    $(formMessages).text(data.responseText);

                } else {

                    $(formMessages).text('Oops! An error occured and your message could not be sent.');

                }

            });

    });



})(jQuery);
;
/* assets/js/main.js */
/**

*

* -----------------------------------------------------------------------------

*

* Template : Educavo - Education HTML Template

* Author : rs-theme

* Author URI : http://www.rstheme.com/

*

* -----------------------------------------------------------------------------

*

**/

(function ($) {

    "use strict";

    // sticky menu

    var header = $('.menu-sticky');

    var win = $(window);



    win.on('scroll', function () {

        var scroll = win.scrollTop();

        if (scroll < 1) {

            header.removeClass("sticky");

        } else {

            header.addClass("sticky");

        }



        $("section").each(function () {

            var elementTop = $(this).offset().top - $('#rs-header').outerHeight();

            if (scroll >= elementTop) {

                $(this).addClass('loaded');

            }

        });



    });



    //window load

    $(window).on('load', function () {

        $("#loading").delay(1500).fadeOut(500);

        $("#loading-center").on('click', function () {

            $("#loading").fadeOut(500);

        })

    })



    // Parallax Stuff

    if ($("#stuff").length) {

        var stuff = $('#stuff').get(0);

        var parallaxInstance = new Parallax(stuff);

    }



    // onepage nav

    var navclose = $('#onepage-menu');

    if (navclose.length) {

        $(".nav-menu li a").on("click", function () {

            if ($(".showhide").is(":visible")) {

                $(".showhide").trigger("click");

            }

        });



        if ($.fn.onePageNav) {

            $(".nav-menu").onePageNav({

                currentClass: "active-menu"

            });

        }

    }



    //Testimonials Slider

    var sliderfor = $('.slider-for');

    if (sliderfor.length) {

        $('.slider-for').slick({

            slidesToShow: 1,

            slidesToScroll: 1,

            arrows: true,

            fade: true,

            asNavFor: '.slider-nav',

            autoplay: true

        });

    }

    var slidernav = $('.slider-nav');

    if (slidernav.length) {

        $('.slider-nav').slick({

            slidesToShow: 3,

            slidesToScroll: 1,

            asNavFor: '.slider-for',

            dots: false,

            centerMode: true,

            focusOnSelect: true,

        });

    }



    // collapse hidden  

    var navMain = $(".navbar-collapse");

    navMain.on("click", "a:not([data-toggle])", null, function () {

        navMain.collapse('hide');

    });



    // video 
    if ($('.player').length) {
        $(".player").YTPlayer();
    }

    // wow init
    new WOW().init();

    // image loaded portfolio init
    var gridfilter = $('.grid');
    if (gridfilter.length) {
        $('.grid').imagesLoaded(function () {
            var $grid = $('.grid').isotope({
                itemSelector: '.grid-item',
                percentPosition: true,
                masonry: {
                    columnWidth: '.grid-item',
                }
            });

            var filters = {};

            $('.gridFilter').on('click', 'button', function (event) {
                var $this = $(this);
                // get group ID
                var $buttonGroup = $this.parents('.gridFilter');
                var filterGroup = $buttonGroup.attr('id') || 'defaultGroup';
                // set filter for group
                filters[filterGroup] = $this.attr('data-filter');

                // combine filters
                var filterValue = '';
                for (var prop in filters) {
                    if (filters[prop] && filters[prop] !== '*') {
                        filterValue += filters[prop];
                    }
                }

                // if empty, show all
                if (!filterValue) {
                    filterValue = '*';
                }

                $grid.isotope({
                    filter: filterValue
                });

                // Also update dropdown UI text if clicking inside dropdown
                if ($buttonGroup.hasClass('dropdown-menu')) {
                    $buttonGroup.siblings('.dropdown-toggle').text($this.text());
                }

                $this.siblings('.active').removeClass('active');
                $this.addClass('active');
                event.preventDefault();
            });
        });
    }



    // magnificPopup init

    var imagepopup = $('.image-popup');

    if (imagepopup.length) {

        $('.image-popup').magnificPopup({

            type: 'image',

            callbacks: {

                beforeOpen: function () {

                    this.st.image.markup = this.st.image.markup.replace('mfp-figure', 'mfp-figure animated zoomInDown');

                }

            },

            gallery: {

                enabled: true

            }

        });

    }



    // Get a quote popup

    var popupquote = $('.popup-quote');

    if (popupquote.length) {

        $('.popup-quote').magnificPopup({

            type: 'inline',

            preloader: false,

            focus: '#qname',

            removalDelay: 500,

            callbacks: {

                beforeOpen: function () {

                    this.st.mainClass = this.st.el.attr('data-effect');

                    if (win.width() < 800) {

                        this.st.focus = false;

                    } else {

                        this.st.focus = '#qname';

                    }

                }

            }

        });

    }



    //preloader

    $(window).on('load', function () {

        $("#loader").delay(1000).fadeOut(500);

    })



    //Videos popup jQuery 

    var popupvideos = $('.popup-videos');

    if (popupvideos.length) {

        $('.popup-videos').magnificPopup({

            disableOn: 10,

            type: 'iframe',

            mainClass: 'mfp-fade',

            removalDelay: 160,

            preloader: false,

            fixedContentPos: false

        });

    }



    /*-------------------------------------

        OwlCarousel

    -------------------------------------*/

    $('.rs-carousel').each(function () {

        var owlCarousel = $(this),

            loop = owlCarousel.data('loop'),

            items = owlCarousel.data('items'),

            margin = owlCarousel.data('margin'),

            stagePadding = owlCarousel.data('stage-padding'),

            autoplay = owlCarousel.data('autoplay'),

            autoplayTimeout = owlCarousel.data('autoplay-timeout'),

            smartSpeed = owlCarousel.data('smart-speed'),

            dots = owlCarousel.data('dots'),

            nav = owlCarousel.data('nav'),

            navSpeed = owlCarousel.data('nav-speed'),

            xsDevice = owlCarousel.data('mobile-device'),

            xsDeviceNav = owlCarousel.data('mobile-device-nav'),

            xsDeviceDots = owlCarousel.data('mobile-device-dots'),

            smDevice = owlCarousel.data('ipad-device'),

            smDeviceNav = owlCarousel.data('ipad-device-nav'),

            smDeviceDots = owlCarousel.data('ipad-device-dots'),

            smDevice2 = owlCarousel.data('ipad-device2'),

            smDeviceNav2 = owlCarousel.data('ipad-device-nav2'),

            smDeviceDots2 = owlCarousel.data('ipad-device-dots2'),

            mdDevice = owlCarousel.data('md-device'),

            centerMode = owlCarousel.data('center-mode'),

            HoverPause = owlCarousel.data('hoverpause'),

            mdDeviceNav = owlCarousel.data('md-device-nav'),

            mdDeviceDots = owlCarousel.data('md-device-dots');

        owlCarousel.owlCarousel({

            loop: (loop ? true : false),

            items: (items ? items : 4),

            lazyLoad: true,

            center: (centerMode ? true : false),

            autoplayHoverPause: (HoverPause ? true : false),

            margin: (margin ? margin : 0),

            //stagePadding: (stagePadding ? stagePadding : 0),

            autoplay: (autoplay ? true : false),

            autoplayTimeout: (autoplayTimeout ? autoplayTimeout : 1000),

            smartSpeed: (smartSpeed ? smartSpeed : 250),

            dots: (dots ? true : false),

            nav: (nav ? true : false),

            navText: ["<i class='fa fa-angle-left'></i>", "<i class='fa fa-angle-right'></i>"],

            navSpeed: (navSpeed ? true : false),

            responsiveClass: true,

            responsive: {

                0: {

                    items: (xsDevice ? xsDevice : 1),

                    nav: (xsDeviceNav ? true : false),

                    dots: (xsDeviceDots ? true : false),

                    center: false,

                },

                576: {

                    items: (smDevice2 ? smDevice2 : 2),

                    nav: (smDeviceNav2 ? true : false),

                    dots: (smDeviceDots2 ? true : false),

                    center: false,

                },

                768: {

                    items: (smDevice ? smDevice : 3),

                    nav: (smDeviceNav ? true : false),

                    dots: (smDeviceDots ? true : false),

                    center: false,

                },

                992: {

                    items: (mdDevice ? mdDevice : 4),

                    nav: (mdDeviceNav ? true : false),

                    dots: (mdDeviceDots ? true : false),

                }

            }

        });

    });



    // Skill bar 

    var skillbar = $('.skillbar');

    if (skillbar.length) {

        $('.skillbar').skillBars({

            from: 0,

            speed: 4000,

            interval: 100,

            decimals: 0,

        });

    }



    // Counter Up

    var counter = $('.rs-count');

    if (counter.length) {

        $('.rs-count').counterUp({

            delay: 20,

            time: 1500

        });

    }



    // scrollTop init	

    var totop = $('#scrollUp');

    win.on('scroll', function () {

        if (win.scrollTop() > 150) {

            totop.fadeIn();

        } else {

            totop.fadeOut();

        }

    });

    totop.on('click', function () {

        $("html,body").animate({

            scrollTop: 0

        }, 500)

    });



    //canvas menu

    var navexpander = $('#nav-expander');

    if (navexpander.length) {

        $('#nav-expander').on('click', function (e) {

            e.preventDefault();

            $('body').toggleClass('nav-expanded');

        });

    }

    var navclose = $('#nav-close');

    if (navclose.length) {

        $('#nav-close').on('click', function (e) {

            e.preventDefault();

            $('body').removeClass('nav-expanded');

        });

    }





    // View Course

    $('.course-view-part .view-icons .view-grid').on('click', function (e) {

        e.preventDefault();

        $('.rs-popular-courses').removeClass('list-view');

    });

    $('.course-view-part .view-icons .view-list').on('click', function (e) {

        e.preventDefault();

        $('.rs-popular-courses').addClass('list-view');

    });





    /*----------------------------

    single-productjs active

    ------------------------------ */

    var singleproductimage = $('.single-product-image');

    if (singleproductimage.length) {

        $('.single-product-image').slick({

            slidesToShow: 1,

            slidesToScroll: 1,

            arrows: false,

            fade: true,

            asNavFor: '.single-product-nav'

        });

    }



    var singleproductnav = $('.single-product-nav');

    if (singleproductnav.length) {

        $('.single-product-nav').slick({

            slidesToShow: 3,

            asNavFor: '.single-product-image',

            dots: false,

            focusOnSelect: true,

            centerMode: false,

            responsive: [

                {

                    breakpoint: 768,

                    settings: {

                        slidesToShow: 2

                    }

                },

                {

                    breakpoint: 591,

                    settings: {

                        slidesToShow: 2

                    }

                }

            ]

        });

    }



    // categories btn

    $('.cat-menu-inner').hide();

    $('.cat-btn').on('click', function () {

        $('.cat-menu-inner').slideToggle();

    })



    var tilt = $('.js-tilt');

    if (tilt.length) {

        const tilt = $('.js-tilt').tilt();

    }





})(jQuery);
